import math

def binomial_dist(k, n, p):
    coeff = math.comb(n, k)
    return coeff * (p**k) * ((1 - p)**(n - k))

if __name__ == "__main__":
    print(f"Prob: {binomial_dist(2, 4, 0.5)}")
